#[cfg(test)]
mod breathing_rate_edge_cases {
    use wifi_densepose_mat::detection::breathing::BreathingDetector;

    #[test]
    fn zero_bpm_is_classified_critical() {
        let detector = BreathingDetector::default();
        // flat-line signal — no breathing detected
        let signal = vec![0.0f32; 1000];
        let result = detector.classify(&signal).unwrap();
        assert_eq!(result.triage_category, TriageCategory::Immediate);
    }

    #[test]
    fn agonal_breathing_rate_triggers_immediate() {
        // < 6 BPM is agonal; simulate 3 BPM signal
        let detector = BreathingDetector::default();
        let signal = generate_breathing_signal(3.0, 1000, 100.0); // 3 BPM, 1000 samples @ 100 Hz
        let result = detector.classify(&signal).unwrap();
        assert_eq!(result.triage_category, TriageCategory::Immediate);
    }

    #[test]
    fn normal_breathing_is_classified_minor() {
        let detector = BreathingDetector::default();
        let signal = generate_breathing_signal(15.0, 1000, 100.0); // 15 BPM
        let result = detector.classify(&signal).unwrap();
        assert_eq!(result.triage_category, TriageCategory::Minor);
    }

    #[test]
    fn all_nan_signal_returns_error_not_panic() {
        let detector = BreathingDetector::default();
        let signal = vec![f32::NAN; 1000];
        let result = detector.classify(&signal);
        assert!(result.is_err(), "NaN input must be caught, not panic");
    }

    fn generate_breathing_signal(bpm: f32, samples: usize, sample_rate: f32) -> Vec<f32> {
        let freq = bpm / 60.0;
        (0..samples)
            .map(|i| (2.0 * std::f32::consts::PI * freq * i as f32 / sample_rate).sin())
            .collect()
    }
}

#[cfg(test)]
mod alert_deduplication {
    use wifi_densepose_mat::alerting::{AlertDispatcher, Alert, TriageCategory};
    use std::time::Duration;

    #[test]
    fn duplicate_alerts_within_window_are_suppressed() {
        let mut dispatcher = AlertDispatcher::new();
        let alert = Alert::new("survivor-1", TriageCategory::Immediate);
        dispatcher.dispatch(alert.clone());
        dispatcher.dispatch(alert.clone()); // same survivor, same category
        assert_eq!(dispatcher.queued_count(), 1, "duplicate must be deduplicated");
    }

    #[test]
    fn escalation_from_minor_to_immediate_is_forwarded() {
        let mut dispatcher = AlertDispatcher::new();
        dispatcher.dispatch(Alert::new("survivor-1", TriageCategory::Minor));
        dispatcher.dispatch(Alert::new("survivor-1", TriageCategory::Immediate));
        // escalation is not a duplicate — must pass through
        assert!(dispatcher.last_alert_for("survivor-1").map(|a| a.category) == Some(TriageCategory::Immediate));
    }
}

#[cfg(test)]
mod kalman_tracker_edge_cases {
    use wifi_densepose_mat::tracking::KalmanTracker;

    #[test]
    fn position_jump_does_not_corrupt_state() {
        let mut tracker = KalmanTracker::new();
        tracker.update([1.0, 1.0, 0.5]);  // initial position
        tracker.update([50.0, 50.0, 0.5]); // physically impossible jump
        let pos = tracker.estimated_position();
        // should not panic; should clamp or flag anomaly
        assert!(pos.iter().all(|v| v.is_finite()));
    }

    #[test]
    fn lost_track_resumes_on_re_detection() {
        let mut tracker = KalmanTracker::new();
        tracker.update([1.0, 1.0, 0.5]);
        // simulate 10 missed frames
        for _ in 0..10 { tracker.predict(); }
        assert_eq!(tracker.state(), TrackState::Lost);
        tracker.update([1.1, 1.1, 0.5]); // re-detected nearby
        assert_eq!(tracker.state(), TrackState::Confirmed);
    }
}
