    fn zero_feature_vectors_do_not_produce_nan() {
        let attn = CrossViewpointAttention::new(2);
        let features = vec![[0.0f32; 64], [0.0f32; 64]];
        let weights = attn.compute_weights(&features);
        assert!(weights.iter().all(|w| w.is_finite()));
    }
}

