#[cfg(test)]
mod phase_align_tests {
    use wifi_densepose_signal::ruvsense::phase_align::PhaseAligner;

    #[test]
    fn phase_at_plus_pi_does_not_wrap_incorrectly() {
        let aligner = PhaseAligner::new();
        let phases = vec![std::f32::consts::PI - 0.001, std::f32::consts::PI + 0.001];
        let aligned = aligner.align(&phases);
        // jump across ±π boundary must be handled continuously
        let diff = (aligned[1] - aligned[0]).abs();
        assert!(diff < 0.01, "phase jump at ±π must be < 0.01 rad after alignment");
    }

    #[test]
