        let aligner = PhaseAligner::new();
        let phases = vec![1.5f32];
        let aligned = aligner.align(&phases);
        assert_eq!(aligned.len(), 1);
        assert!((aligned[0] - 1.5).abs() < 1e-6);
    }

    #[test]
    fn empty_phase_array_returns_empty() {
        let aligner = PhaseAligner::new();
        let aligned = aligner.align(&[]);
        assert!(aligned.is_empty());
    }
}

