#[cfg(test)]
mod film_layer_tests {
    use wifi_densepose_train::geometry::FilmLayer;

    #[test]
    fn film_layer_output_shape_matches_input() {
        let film = FilmLayer::new(64, 32); // 64-dim features, 32-dim condition
        let features = vec![0.5f32; 64];
        let condition = vec![1.0f32; 32];
        let output = film.forward(&features, &condition).unwrap();
        assert_eq!(output.len(), 64, "FiLM output must match feature dimensionality");
    }

    #[test]
    fn film_layer_zero_condition_acts_as_identity() {
        let film = FilmLayer::new(64, 32);
        let features = vec![1.0f32; 64];
        let zero_condition = vec![0.0f32; 32];
        let output = film.forward(&features, &zero_condition).unwrap();
        // scale=1, shift=0 → identity; output ≈ input
        for (o, f) in output.iter().zip(features.iter()) {
            assert!((o - f).abs() < 0.1, "zero condition should approximate identity");
        }
    }
}

