#[cfg(test)]
mod rapid_adaptation_tests {
    use wifi_densepose_train::rapid_adapt::RapidAdapter;

    #[test]
    fn adapter_updates_on_single_sample() {
        let mut adapter = RapidAdapter::new(5); // 5 adaptation steps
        let csi_sample = vec![0.1f32; 56 * 3];
        let pose_label = vec![0.5f32; 17 * 2]; // 17 keypoints × (x, y)
        let result = adapter.adapt_step(&csi_sample, &pose_label);
        assert!(result.is_ok());
    }

    #[test]
    fn adapter_with_zero_steps_is_no_op() {
        let adapter = RapidAdapter::new(0);
        // 0 adaptation steps → weights unchanged
        let initial_weights = adapter.clone_weights();
        let _ = adapter.adapt_step(&vec![0.1f32; 168], &vec![0.5f32; 34]);
        assert_eq!(adapter.clone_weights(), initial_weights);
    }
