#[cfg(test)]
mod bearer_auth_tests {
    use wifi_densepose_sensing_server::auth::{BearerValidator, TokenError};

    #[test]
    fn missing_authorization_header_returns_unauthorized() {
        let validator = BearerValidator::new("secret-token");
        let result = validator.validate(None);
        assert!(matches!(result, Err(TokenError::Missing)));
    }

    #[test]
    fn wrong_token_is_rejected() {
        let validator = BearerValidator::new("correct-token");
        let result = validator.validate(Some("Bearer wrong-token"));
        assert!(matches!(result, Err(TokenError::Invalid)));
    }

    #[test]
    fn malformed_header_without_bearer_prefix_is_rejected() {
        let validator = BearerValidator::new("token");
        let result = validator.validate(Some("token")); // missing "Bearer " prefix
        assert!(matches!(result, Err(TokenError::Malformed)));
    }

    #[test]
    fn correct_token_is_accepted() {
        let validator = BearerValidator::new("correct-token");
        let result = validator.validate(Some("Bearer correct-token"));
        assert!(result.is_ok());
    }
}

