#[cfg(test)]
mod fall_detection_tests {
    use wifi_densepose_sensing_server::semantic::fall_detector::FallDetector;

    #[test]
    fn no_motion_does_not_trigger_fall() {
        let mut detector = FallDetector::new();
        for _ in 0..30 { // 30 frames of stillness
            detector.update_pose(stationary_pose());
        }
        assert!(!detector.fall_detected());
    }

    #[test]
    fn rapid_downward_velocity_triggers_fall() {
        let mut detector = FallDetector::new();
        // simulate person going from standing (y=1.7m) to prone (y=0.3m) in 3 frames
        for (frame, y) in [(0, 1.7f32), (1, 1.0), (2, 0.3)] {
            detector.update_pose(pose_at_height(y));
        }
        assert!(detector.fall_detected());
    }

    #[test]
    fn sitting_down_slowly_does_not_trigger_fall() {
        let mut detector = FallDetector::new();
        // gradual height decrease over 30 frames is sitting, not falling
        for i in 0..30 {
            let y = 1.7f32 - (i as f32 * 0.04); // ~1.2m drop over 30 frames
            detector.update_pose(pose_at_height(y));
        }
        assert!(!detector.fall_detected());
    }
}
